import { useState, useRef } from 'react';
import { Audio } from 'expo-av';

export type RecordingState = 'idle' | 'recording' | 'transcribing' | 'thinking';

export function useVoiceRecorder() {
  const [state, setState] = useState<RecordingState>('idle');
  const recordingRef = useRef<Audio.Recording | null>(null);

  async function startRecording() {
    await Audio.requestPermissionsAsync();
    await Audio.setAudioModeAsync({
      allowsRecordingIOS: true,
      playsInSilentModeIOS: true,
    });
    const { recording } = await Audio.Recording.createAsync(
      Audio.RecordingOptionsPresets.HIGH_QUALITY
    );
    recordingRef.current = recording;
    setState('recording');
  }

  async function stopRecording(): Promise<string | null> {
    const recording = recordingRef.current;
    if (!recording) return null;
    await recording.stopAndUnloadAsync();
    const uri = recording.getURI();
    recordingRef.current = null;
    return uri ?? null;
  }

  return { state, setState, startRecording, stopRecording };
}

import { Pressable, View, Text, StyleSheet } from 'react-native';
import { useVoiceRecorder } from './useVoiceRecorder';

export function MicButton({ onTranscript }: { onTranscript: (text: string) => void }) {
  const { state, startRecording, stopRecording, setState } = useVoiceRecorder();
  const isRecording = state === 'recording';

  async function handlePressIn() {
    await startRecording();
  }

  async function handlePressOut() {
    setState('transcribing');
    const uri = await stopRecording();
    if (uri) {
      const text = await transcribeAudio(uri);  // Stage 2
      setState('idle');
      onTranscript(text);
    }
  }

  return (
    <Pressable
      onPressIn={handlePressIn}
      onPressOut={handlePressOut}
      style={[styles.mic, isRecording && styles.micActive]}
    >
      <Text style={styles.micIcon}>{isRecording ? '⏺' : '🎙️'}</Text>
    </Pressable>
  );
}

const styles = StyleSheet.create({
  mic: {
    width: 56, height: 56, borderRadius: 28,
    backgroundColor: '#6366f1', justifyContent: 'center', alignItems: 'center',
  },
  micActive: { backgroundColor: '#ef4444', transform: [{ scale: 1.15 }] },
  micIcon: { fontSize: 24 },
});

async function transcribeAudio(uri: string): Promise<string> {
  // Expo's FileSystem uses file:// URIs; FormData in RN accepts them directly
  const formData = new FormData();
  formData.append('file', {
    uri,
    name: 'audio.m4a',
    type: 'audio/m4a',
  } as any);             // RN's FormData accepts object shape here
  formData.append('model', 'whisper-1');
  formData.append('language', 'en');   // omit for auto-detect

  const response = await fetch('https://api.openai.com/v1/audio/transcriptions', {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${process.env.EXPO_PUBLIC_OPENAI_KEY}`,
      // Do NOT set Content-Type — fetch sets it with the boundary automatically
    },
    body: formData,
  });

  if (!response.ok) {
    const err = await response.text();
    throw new Error(`Whisper error: ${err}`);
  }

  const json = await response.json();
  return json.text as string;   // 'Hello, what is the weather today?'
}

import ExpoSpeechRecognitionModule, {
  useSpeechRecognitionEvent,
} from 'expo-speech-recognition';

function useOnDeviceTranscription(onFinal: (text: string) => void) {
  useSpeechRecognitionEvent('result', ev => {
    if (ev.isFinal) {
      onFinal(ev.results[0]?.transcript ?? '');
    }
  });

  function start() {
    ExpoSpeechRecognitionModule.start({
      lang: 'en-US',
      interimResults: true,
    });
  }

  function stop() {
    ExpoSpeechRecognitionModule.stop();
  }

  return { start, stop };
}

import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic({ apiKey: process.env.EXPO_PUBLIC_ANTHROPIC_KEY! });

async function askClaude(
  transcript: string,
  onChunk: (chunk: string) => void
): Promise<string> {
  let fullText = '';
  const stream = client.messages.stream({
    model: 'claude-opus-4-8',
    max_tokens: 512,
    system: 'You are a helpful voice assistant. Keep answers concise (2–3 sentences) since the user will hear them read aloud.',
    messages: [{ role: 'user', content: transcript }],
  });

  for await (const event of stream) {
    if (
      event.type === 'content_block_delta' &&
      event.delta.type === 'text_delta'
    ) {
      const chunk = event.delta.text;
      fullText += chunk;
      onChunk(chunk);
    }
  }
  return fullText;
}

import * as Speech from 'expo-speech';

function speakResponse(text: string, onDone?: () => void) {
  // Stop any ongoing speech first
  Speech.stop();
  Speech.speak(text, {
    language: 'en-US',
    rate: 0.95,        // slightly slower than default (1.0) for clarity
    pitch: 1.0,
    onDone,
    onError: err => console.error('TTS error:', err),
  });
}

// Stop speaking when user presses mic again
function handleMicPress() {
  Speech.stop();
  startRecording();
}

import React, { useState, useRef } from 'react';
import { View, Text, FlatList, StyleSheet } from 'react-native';
import * as Speech from 'expo-speech';
import { MicButton } from './MicButton';
import { askClaude } from './askClaude';
import { transcribeAudio } from './transcribeAudio';

type RecordingState = 'idle' | 'recording' | 'transcribing' | 'thinking';

interface Turn { id: string; role: 'user' | 'assistant'; text: string; }

export default function VoiceChatScreen() {
  const [turns, setTurns] = useState<Turn[]>([]);
  const [status, setStatus] = useState<RecordingState>('idle');
  const abortRef = useRef<AbortController | null>(null);

  async function handleTranscript(uri: string) {
    setStatus('transcribing');
    let transcript: string;
    try {
      transcript = await transcribeAudio(uri);
    } catch {
      setStatus('idle');
      return;
    }

    const userId = Date.now().toString();
    const assistId = (Date.now() + 1).toString();
    setTurns(prev => [
      ...prev,
      { id: userId, role: 'user', text: transcript },
      { id: assistId, role: 'assistant', text: '' },
    ]);

    setStatus('thinking');
    const controller = new AbortController();
    abortRef.current = controller;
    let fullText = '';

    try {
      fullText = await askClaude(transcript, chunk => {
        setTurns(prev =>
          prev.map(t =>
            t.id === assistId ? { ...t, text: t.text + chunk } : t
          )
        );
      });
    } finally {
      setStatus('idle');
      abortRef.current = null;
    }

    // Optionally speak the reply
    speakResponse(fullText);
  }

  const statusLabel = {
    idle: 'Hold to speak',
    recording: 'Recording...',
    transcribing: 'Transcribing...',
    thinking: 'Claude is thinking...',
  }[status];

  return (
    <View style={{ flex: 1, backgroundColor: '#f9fafb' }}>
      <FlatList
        data={turns}
        keyExtractor={t => t.id}
        renderItem={({ item }) => (
          <View style={[
            styles.bubble,
            item.role === 'user' ? styles.userBubble : styles.assistBubble,
          ]}>
            <Text style={item.role === 'user' ? styles.userText : styles.assistText}>
              {item.text || '...'}
            </Text>
          </View>
        )}
        contentContainerStyle={{ padding: 16, flexGrow: 1, justifyContent: 'flex-end' }}
      />
      <View style={styles.bar}>
        <Text style={styles.statusLabel}>{statusLabel}</Text>
        <MicButton
          disabled={status === 'transcribing' || status === 'thinking'}
          onRecordingStop={handleTranscript}
        />
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  bubble: { maxWidth: '80%', borderRadius: 16, padding: 12, marginVertical: 4 },
  userBubble: { alignSelf: 'flex-end', backgroundColor: '#6366f1' },
  assistBubble: { alignSelf: 'flex-start', backgroundColor: '#fff', borderWidth: 1, borderColor: '#e5e7eb' },
  userText: { color: '#fff', fontSize: 15 },
  assistText: { color: '#111827', fontSize: 15 },
  bar: { flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between', padding: 16, borderTopWidth: 1, borderColor: '#e5e7eb', backgroundColor: '#fff' },
  statusLabel: { fontSize: 13, color: '#6b7280', flex: 1, marginRight: 12 },
});

